metadata.correct:
package sandbox

import "strings"

func CountVowels(s string) int {
	n := 0
	for _, c := range strings.ToLower(s) {
		switch c {
		case 'a', 'e', 'i', 'o', 'u':
			n++
		}
	}
	return n
}

